INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic) VALUES
('63b4174a-a643-53e2-a49c-dcaa8e07608a', '0c540794-c18e-48dc-964e-63a65a1ec1ee', 'The shop is ___ the bank and the school.', '這間商店在銀行和學校之間。', 'between', 'among', 'behind', 'near', 'be- (在...之間) + tween (兩者之中) → 用於兩者之間。', 'A and B 之間，選 between。'),
('e906caaa-020a-534d-aa53-79bb1373d456', 'ac13fde8-c53f-49dd-bdca-618241eb7414', 'We are happy ___ excited.', '我們既開心又興奮。', 'and', 'but', 'or', 'so', '連接詞，用於連接兩個對等的形容詞。', 'and 把兩種心情連在一起。'),
('8cdee92e-2a5c-5944-ba15-989bc0645292', 'fb317c3c-8446-4ee4-9bfc-798b3e8a0110', 'We are planning to visit Japan ___ the summer.', '我們計畫在夏天去日本旅遊。', 'in', 'on', 'at', 'through', '用於較長的時間段（如季節、月份、年份）。', '包含在一段大的時間範圍內。'),
('9f5b0393-e1e2-5e97-9d32-d8318ba17e66', 'c5a6bb6c-11be-4f15-9ea7-f6b983edff63', 'Philosophers often debate the mystery of ___.', '哲學家常討論「存在」之謎。', 'being', 'logic', 'truth', 'reason', 'be (存在) + ing (名詞字尾) → 存在、生命體、本質。', '想像「being」就是「正在存在著的狀態」→ 存在、生命。'),
('dcde15d3-8af3-5477-aa03-2fe86da0b2c2', '69c72296-40c5-4d3c-8b3a-6a62df6576c3', 'Excuse me, I think you have picked up ___ wallet by mistake.', '不好意思，我想你拿錯了我的錢包。', 'my', 'your', 'her', 'their', '所有格形容詞 (possessive adjective)', 'my + 名詞 → 我的...');
